mapper.select:
SELECT u.user_name,u.user_code,pb.address,pb.chain_name,pb.coin_symbol,pb.ucid
FROM t_party_blockchain  pb
         LEFT JOIN tz_user u  ON pb.user_name=u.user_name

where
1 =1

    and u.role_name=#{roleName}



    and u.user_name=#{userName} or u.user_code=#{userName}



    and pb.address=#{address}
